//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Cell margins: defaults, per-cell, and exception precedence".
//!
//! Each `#[test]` encodes a Word-consumption / serializer-emission rule mined
//! from ECMA-376 / ISO 29500 / MS-OI29500 for table cell margins (tcMar,
//! tblCellMar, tblPrEx/tblCellMar, tblCellSpacing). A FAILING assertion is NOT a
//! flake to be silenced: it encodes a real Word-compliance gap in the stemma
//! engine. Do not weaken an assertion to make it pass; a fail is the finding.
//!
//! Methodology notes (see workflow brief):
//!  - `xmlContains/xmlOmits/<ordered>` on the re-serialized document.xml are only
//!    valid for markup the serializer ACTIVELY generates/restructures (child
//!    ordering, structural synthesis) or for opens-clean validity. stemma
//!    round-trips UNTOUCHED content byte-verbatim, so these assertions reflect
//!    the verbatim-preservation contract, not Word's render-time normalization.
//!  - Consumption semantics ("pct means width 0", "nil means ignored") are
//!    tested on the READ side (read_accepted/read_rejected text) or via
//!    opens-clean, NOT by asserting the XML drops a verbatim-preserved value.

use std::io::{Read, Write};

use stemma::api::Document;
use zip::write::FileOptions;

// ─── Prelude: zip plumbing + observation helpers ─────────────────────────────

/// Build a minimal valid `.docx` whose `word/document.xml` body is `body_xml`
/// (wrapped in `<w:document><w:body>…</w:body></w:document>`). `extra_parts` are
/// additional `(part_name, xml)` entries (e.g. `word/styles.xml`) that also get
/// a Content-Types override.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-Types: the base defaults + document override, plus an override per
    // extra part (content type derived from the part's file name).
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (name, _) in extra_parts {
        let ct = if name.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if name.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            "application/xml"
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{name}" ContentType="{ct}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, xml) in extra_parts {
            zip.start_file(*name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse `bytes`, re-serialize via the default export options, and return the
/// resulting `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Position-only ordering: every token appears in `haystack` in sequence, with
/// no constraint on what lies between them. Used to assert child-element ORDER
/// where the tokens are open-tag prefixes (e.g. `<w:top`), so the bytes between
/// consecutive tokens are the remainder of the preceding element, not whitespace.
fn in_order(haystack: &str, tokens: &[&str]) -> bool {
    let mut from = 0usize;
    for tok in tokens {
        match haystack[from..].find(tok) {
            Some(rel) => from += rel + tok.len(),
            None => return false,
        }
    }
    true
}

/// Assert `stemma::api::validate` reports no errors for `bytes`.
fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok,
        "{msg} — validate reported issues: {:?}",
        report.issues
    );
}

