/// tcmar_pct_width_margin_ignored_not_relabeled_dxa
/// ISO 29500-1 §17.4.34, §17.4.5; MS-OI29500 §2.1.154
/// A pct/auto-typed per-cell margin SHALL be ignored (width 0 / fall back to
/// default), never reinterpreted as a dxa value. Opens-clean is the daily check;
/// the layout consequence is an oracle question.
#[test]
fn tcmar_pct_width_margin_ignored_not_relabeled_dxa() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="dxa"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/><w:tcMar><w:start w:w="500" w:type="pct"/></w:tcMar></w:tcPr><w:p><w:r><w:t>cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "tcmar_pct_width_margin_ignored_not_relabeled_dxa: a cell whose only tcMar entry is a pct-typed leading margin is well-formed; Word ignores the pct value but opens without repair (ISO 29500-1 §17.4.34 / MS-OI29500 §2.1.154)",
    );
}

/// tblcellmar_default_bottom_only_applies_and_roundtrips
/// ISO 29500-1 §17.4.42, §17.4.5
/// A bottom-only tblCellMar default must round-trip as exactly one w:bottom child
/// (value 360), not fabricate the other sides nor drop the value.
///
/// NOTE: this asserts on reserialize() of an unedited document. For a value
/// stemma preserves verbatim this is a valid preservation check (the 360 must
/// survive). The "exactly one child" shape is likewise a structural-fidelity
/// claim: the engine must not synthesize the missing sides.
#[test]
fn tblcellmar_default_bottom_only_applies_and_roundtrips() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="dxa"/><w:tblCellMar><w:bottom w:w="360" w:type="dxa"/></w:tblCellMar></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"<w:bottom w:w="360" w:type="dxa"/>"#),
        "tblcellmar_default_bottom_only_applies_and_roundtrips: the bottom-only table default (ISO 29500-1 §17.4.5) must survive regeneration with its exact value 360. XML was: {xml}"
    );
    // Exactly one bottom child, no fabricated top/left/right sides: the canonical
    // bottom-only tblCellMar must appear verbatim (adjacent, single child).
    assert!(
        xml.contains(r#"<w:tblCellMar><w:bottom w:w="360" w:type="dxa"/></w:tblCellMar>"#),
        "tblcellmar_default_bottom_only_applies_and_roundtrips: only the bottom side was specified; the engine must not fabricate top/left/right defaults — tblCellMar contains exactly the one bottom child (ISO 29500-1 §17.4.5 example). XML was: {xml}"
    );
    assert_opens_clean(
        &b,
        "tblcellmar_default_bottom_only_applies_and_roundtrips: tblCellMar with a single bottom child is schema-valid CT_TblCellMar; Word opens without repair (ISO 29500-1 §17.4.5)",
    );
}

/// tcmar_overrides_table_default_per_side_independently
/// ISO 29500-1 §17.4.68, §17.4.42
/// A per-cell tcMar overrides the table tblCellMar default. The override values
/// (720), not the table default (144), govern the cell. Opens-clean is the daily
/// check.
#[test]
fn tcmar_overrides_table_default_per_side_independently() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="dxa"/><w:tblCellMar><w:top w:w="144" w:type="dxa"/><w:left w:w="144" w:type="dxa"/><w:bottom w:w="144" w:type="dxa"/><w:right w:w="144" w:type="dxa"/></w:tblCellMar></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/><w:tcMar><w:top w:w="720" w:type="dxa"/><w:left w:w="720" w:type="dxa"/><w:bottom w:w="720" w:type="dxa"/><w:right w:w="720" w:type="dxa"/></w:tcMar></w:tcPr><w:p><w:r><w:t>cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "tcmar_overrides_table_default_per_side_independently: a table default plus a per-cell override are both schema-valid; Word opens without repair (ISO 29500-1 §17.4.68 / §17.4.42)",
    );
}

/// cell_margin_default_side_pct_type_opens_clean
/// ISO 29500-1 §17.4.34; MS-OI29500 §2.1.146
/// A pct-typed table-default leading margin is accepted (width 0), document opens
/// clean, and cell text content is untouched.
#[test]
fn cell_margin_default_side_pct_type_opens_clean() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="dxa"/><w:tblCellMar><w:start w:w="50" w:type="pct"/><w:top w:w="100" w:type="dxa"/></w:tblCellMar></w:tblPr><w:tblGrid><w:gridCol w:w="2500"/><w:gridCol w:w="2500"/></w:tblGrid><w:tr><w:tc><w:tcPr/><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc><w:tc><w:tcPr/><w:p><w:r><w:t>B</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "cell_margin_default_side_pct_type_opens_clean: MS-OI29500 §2.1.146 — Word treats a pct-typed margin width as 0 rather than failing, so the document is valid (ISO 29500-1 §17.4.34)",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    // The spec's "AB" is the concatenation of the two cell texts; stemma's read
    // view separates cells with whitespace (a rendering choice, not content), so
    // compare with inter-cell whitespace collapsed away.
    assert_eq!(
        accepted.split_whitespace().collect::<String>(),
        "AB",
        "cell_margin_default_side_pct_type_opens_clean: the pct-typed margin affects only layout width (Word reads it as 0); cell text content is untouched, so the accepted read view yields the two cell texts (ISO 29500-1 §17.4.34 / MS-OI29500 §2.1.146). Got: {accepted:?}"
    );
}

