/// tblprex_cell_margin_exception_applied_to_row
/// ISO 29500-1 §17.4.41, §17.4.42
/// A row-level tblPrEx/tblCellMar (144) overrides the table default (50) for that
/// row and must not be silently dropped. stemma has no tblPrEx parse/serialize
/// path, so the 144 exception is expected to be lost on structural reserialize —
/// this is the gap the spec hunts.
///
/// NOTE: a verbatim passthrough would preserve the 144 too, so this xmlContains
/// is a real test of whether stemma drops tblPrEx. A PASS means the 144 survived
/// (verbatim or modeled); a FAIL means it was dropped, the documented gap.
#[test]
fn tblprex_cell_margin_exception_applied_to_row() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/><w:tblCellMar><w:top w:w="50" w:type="dxa"/><w:start w:w="50" w:type="dxa"/><w:bottom w:w="50" w:type="dxa"/><w:end w:w="50" w:type="dxa"/></w:tblCellMar></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tblPrEx><w:tblCellMar><w:top w:w="144" w:type="dxa"/><w:start w:w="144" w:type="dxa"/><w:bottom w:w="144" w:type="dxa"/><w:end w:w="144" w:type="dxa"/></w:tblCellMar></w:tblPrEx><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:w="144""#),
        "tblprex_cell_margin_exception_applied_to_row: the row's tblPrEx/tblCellMar exception (144tw) governs that row's cell margins (ISO 29500-1 §17.4.41); a faithful engine must preserve the 144 exception, not drop it back to the table default 50tw. XML was: {xml}"
    );
    assert_opens_clean(
        &b,
        "tblprex_cell_margin_exception_applied_to_row: the serialized table with row exceptions must open in Word without repair (ISO 29500-1 §17.4.41 / §17.4.42)",
    );
}

/// tcmar_serialized_side_order_top_left_bottom_right
/// ISO 29500-1 §A.1 (CT_TcMar), §17.4.68
/// When the engine emits w:tcMar its side children must be in schema order: top,
/// leading (start/left), bottom, trailing (end/right).
#[test]
fn tcmar_serialized_side_order_top_left_bottom_right() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/><w:tcMar><w:top w:w="100" w:type="dxa"/><w:start w:w="200" w:type="dxa"/><w:bottom w:w="300" w:type="dxa"/><w:end w:w="400" w:type="dxa"/></w:tcMar></w:tcPr><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // CT_TcMar mandates top, then leading (left|start), then bottom, then
    // trailing (right|end). stemma normalizes start->left / end->right, so accept
    // either spelling at the leading/trailing positions.
    let order_left = in_order(
        &xml,
        &[
            "<w:tcMar>",
            "<w:top",
            "<w:left",
            "<w:bottom",
            "<w:right",
            "</w:tcMar>",
        ],
    );
    let order_start = in_order(
        &xml,
        &[
            "<w:tcMar>",
            "<w:top",
            "<w:start",
            "<w:bottom",
            "<w:end",
            "</w:tcMar>",
        ],
    );
    assert!(
        order_left || order_start,
        "tcmar_serialized_side_order_top_left_bottom_right: CT_TcMar mandates the side sequence top, leading, bottom, trailing; the serialized tcMar must match this order to be schema-valid (ISO 29500-1 §A.1 / §17.4.68). XML was: {xml}"
    );
    assert_opens_clean(
        &b,
        "tcmar_serialized_side_order_top_left_bottom_right: a schema-ordered tcMar opens in Word without repair (ISO 29500-1 §A.1)",
    );
}

/// tcmar_start_end_aliases_accepted_and_applied
/// ISO 29500-1 §A.1 (CT_TcMar transitional), §17.4.68, §17.4.34
/// The leading/trailing margins authored with w:start / w:end must be accepted,
/// applied, and the values (720 / 360) preserved through serialization (stemma
/// maps start->left, end->right).
#[test]
fn tcmar_start_end_aliases_accepted_and_applied() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/><w:tcMar><w:start w:w="720" w:type="dxa"/><w:end w:w="360" w:type="dxa"/></w:tcMar></w:tcPr><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:w="720""#),
        "tcmar_start_end_aliases_accepted_and_applied: the leading-margin value authored via w:start (720tw) must be preserved through serialization; dropping it would lose the cell's leading margin (ISO 29500-1 §17.4.34, CT_TcMar §A.1). XML was: {xml}"
    );
    assert!(
        xml.contains(r#"w:w="360""#),
        "tcmar_start_end_aliases_accepted_and_applied: the trailing-margin value authored via w:end (360tw) must likewise be preserved; the alias is schema-valid and not ignorable (ISO 29500-1 §17.4.68, CT_TcMar §A.1). XML was: {xml}"
    );
    assert_opens_clean(
        &b,
        "tcmar_start_end_aliases_accepted_and_applied: a tcMar using start/end (or normalized to left/right) must open in Word without repair (ISO 29500-1 §A.1)",
    );
}

// ─── Oracle-resolved verbatim-passthrough guards ────────────────
// These three pin the consumption-vs-save boundary: an UNEDITED parse->serialize
// round-trips document.xml byte-verbatim, so out-of-CT_TblCellMar/CT_TcMar-order
// margin children and w:start/w:end aliases survive un-normalized. The open
// question was whether real Word repairs such a verbatim doc. ORACLE-CONFIRMED
// (Word /validate: repaired=false for all three) — Word opens clean, so the
// verbatim contract is correct and validate() must NOT flag these. (The
// regeneration path — project/apply/diff — independently emits canonical schema
// order; that is covered by tcmar_serialized_side_order_top_left_bottom_right.)

/// Table-default `tblCellMar` children authored out of CT_TblCellMar sequence
/// (bottom, right, top, left) open clean — Word does not repair the verbatim doc.
#[test]
fn tblcellmar_out_of_schema_order_opens_clean_verbatim() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="dxa"/><w:tblCellMar><w:bottom w:w="111" w:type="dxa"/><w:right w:w="222" w:type="dxa"/><w:top w:w="333" w:type="dxa"/><w:left w:w="444" w:type="dxa"/></w:tblCellMar></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr/><w:p><w:r><w:t>cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "out-of-order table-default tblCellMar children are well-formed; an unedited doc round-trips verbatim and real Word opens it without repair (oracle /validate: repaired=false). validate() must not flag the verbatim path (ISO 29500-1 §17.4.42, §A.1)",
    );
}

/// Table-default `tblCellMar` using `w:start`/`w:end` aliases (un-normalized to
/// left/right on the verbatim path) opens clean — Word does not repair.
#[test]
fn tblcellmar_start_end_aliases_open_clean_verbatim() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="dxa"/><w:tblCellMar><w:start w:w="240" w:type="dxa"/><w:end w:w="480" w:type="dxa"/></w:tblCellMar></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr/><w:p><w:r><w:t>cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "w:start/w:end are transitional-valid aliases; stemma round-trips an unedited table verbatim (no normalization) and real Word opens it without repair (oracle /validate: repaired=false) (ISO 29500-1 §17.4.42, §A.1)",
    );
}

/// Per-cell `tcMar` children authored out of CT_TcMar sequence open clean — Word
/// does not repair the verbatim doc.
#[test]
fn tcmar_out_of_schema_order_opens_clean_verbatim() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/><w:tcMar><w:right w:w="9" w:type="dxa"/><w:bottom w:w="42" w:type="dxa"/><w:left w:w="76" w:type="dxa"/><w:top w:w="108" w:type="dxa"/></w:tcMar></w:tcPr><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "out-of-order per-cell tcMar children are well-formed; an unedited doc round-trips verbatim and real Word opens it without repair (oracle /validate: repaired=false) (ISO 29500-1 §17.4.68, §A.1)",
    );
}
